    'p.kali_miri_powder.desc':       '\u0924\u0940\u0935\u094d\u0930 \u0909\u0937\u094d\u0923\u0924\u093e \u0906\u0923\u093f \u0938\u0941\u0917\u0902\u0927\u093e\u0938\u093e\u0920\u0940 \u092c\u093e\u0930\u0940\u0915 \u0915\u093e\u0933\u0940 \u092e\u093f\u0930\u0940 \u092a\u093e\u0935\u0921\u0930.',
