    'p.mirchi_powder.desc':          '\u0935\u094d\u092f\u0902\u091c\u0928\u093e\u0902\u0928\u093e \u0930\u0902\u0917 \u0906\u0923\u093f \u0924\u093f\u0916\u091f\u092a\u0923\u093e \u0926\u0947\u0923\u093e\u0930\u0947 \u0924\u0947\u091c\u0938\u094d\u0935\u0940 \u0932\u093e\u0932 \u092e\u093f\u0930\u091a\u0940 \u092a\u093e\u0935\u0921\u0930.',
    'p.chicken_lollipop_masala.desc':'\u0915\u0941\u0930\u0915\u0941\u0930\u0940\u0924 \u0906\u0923\u093f \u0930\u0938\u093e\u0933\u0942 \u091a\u093f\u0915\u0928 \u0932\u0949\u0932\u0940\u092a\u0949\u092a\u0938\u093e\u0920\u0940 \u0924\u093f\u0916\u091f \u092e\u0938\u093e\u0932\u093e \u092e\u093f\u0936\u094d\u0930\u0923.',
    'p.sabji_masala.desc':           '\u0938\u0941\u0915\u0940 \u0906\u0923\u093f \u0930\u0936\u094d\u0936\u093e\u091a\u094d\u092f\u093e \u092d\u093e\u091c\u094d\u092f\u093e\u0902\u0938\u093e\u0920\u0940 \u0938\u0902\u0924\u0941\u0932\u093f\u0924 \u0930\u094b\u091c\u091a\u093e \u092e\u0938\u093e\u0932\u093e.',
    'p.veg_biryani_masala.desc':     '\u0938\u0941\u0917\u0902\u0927\u093f\u0924 \u0935\u0947\u091c \u092c\u093f\u0930\u092f\u093e\u0923\u0940 \u092c\u0928\u0935\u0923\u094d\u092f\u093e\u0938\u093e\u0920\u0940 \u092e\u0938\u093e\u0932\u094d\u092f\u093e\u0902\u091a\u0947 \u0938\u0941\u0917\u0902\u0927\u093f\u0924 \u092e\u093f\u0936\u094d\u0930\u0923.',
